local CONFIG = {
    USUARIO = "FelipeDarks",
    REPOSITORIO = "spider",
    ARQUIVO = "script.lua",
    VERSAO = "1.0.0"
}

local function autoUpdate()
    local url = "https://raw.githubusercontent.com/" .. CONFIG.USUARIO .. "/" .. CONFIG.REPOSITORIO .. "/main/" .. CONFIG.ARQUIVO
    
    local sucesso, resposta = pcall(function()
        return game:HttpGet(url)
    end)
    
    if sucesso and resposta and #resposta > 100 then
        local novaVersao = resposta:match('VERSAO%s*=%s*"([^"]+)"')
        
        if novaVersao and novaVersao ~= CONFIG.VERSAO then
            print("🕷️ Nova versao encontrada: v" .. novaVersao)
            print("🔄 Atualizando automaticamente...")
            loadstring(resposta)()
            return true
        else
            print("🕷️ Script atualizado! v" .. CONFIG.VERSAO)
        end
    else
        print("🕷️ Usando versao local v" .. CONFIG.VERSAO)
    end
    return false
end

